class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        n = len(s)
        # Prefix sums for ones and zeros
        prefix_ones = [0] * (n + 1)
        prefix_zeros = [0] * (n + 1)

        for i in range(n):
            prefix_ones[i + 1] = prefix_ones[i] + (1 if s[i] == '1' else 0)
            prefix_zeros[i + 1] = prefix_zeros[i] + (1 if s[i] == '0' else 0)

        count = 0
        # Iterate over all possible substrings
        for i in range(n):
            for j in range(i, n):
                ones = prefix_ones[j + 1] - prefix_ones[i]
                zeros = prefix_zeros[j + 1] - prefix_zeros[i]
                if ones >= zeros * zeros:
                    count += 1

        return count
